import { useState } from 'react';
import { RotateCcw, AlertCircle, Send, Loader2, CheckCircle2 } from 'lucide-react';

// ⚠️ הדבק/י כאן את ה-Web App URL מ-Google Apps Script:
const WEBHOOK_URL = "https://script.google.com/macros/s/AKfycbz497YxYAavulPofY01-lHq2-2xJ_8ZgO-DmCZAzUgIVcCMHOCTuuwS2sGq0SYMRdTv/exec";

// כתובת המייל לפניות בנושא פרטיות (מופיעה בסעיף ההסכמה):
const FYM_EMAIL = "misrad.fym@gmail.com";

const FYM_LOGO = "data:image/png;base64,";

export default function App() {
  const [formData, setFormData] = useState({
    childName: '',
    gender: '',
    fatherName: '',
    motherName: '',
    maritalStatus: '',
    maritalStatusOther: '',
    address: '',
    age: '',
    grade: '',
    healthFund: '',
    birthDate: '',
    specialEducation: '',
    specialEducationDetails: '',
    interestedInGroup: '',
    additionalInfo: '',
    consent: false
  });

  const [submissionStatus, setSubmissionStatus] = useState('idle'); // idle | submitting | success | error
  const [errorMessage, setErrorMessage] = useState('');
  const [error, setError] = useState('');

  const fieldLabels = {
    childName: 'שם הילד/ה',
    gender: 'מין',
    fatherName: 'שם מלא של האב',
    motherName: 'שם מלא של האם',
    maritalStatus: 'סטטוס משפחתי',
    maritalStatusOther: 'פירוט סטטוס משפחתי',
    address: 'כתובת מדויקת',
    age: 'גיל',
    grade: 'כיתה / גן',
    healthFund: 'קופת חולים',
    birthDate: 'תאריך לידה',
    specialEducation: 'חינוך מיוחד',
    specialEducationDetails: 'פירוט חינוך מיוחד',
    interestedInGroup: 'מעוניינים בקבוצה',
    additionalInfo: 'פרטים נוספים לידיעת המרפאה'
  };

  const handleChange = (field, value) => {
    setFormData({ ...formData, [field]: value });
    if (error) setError('');
    if (submissionStatus === 'error') {
      setSubmissionStatus('idle');
      setErrorMessage('');
    }
  };

  const validate = () => {
    const empty = Object.entries(formData)
      .filter(([k]) => k !== 'consent')
      .filter(([k]) => !(k === 'specialEducationDetails' && formData.specialEducation !== 'כן'))
      .filter(([k]) => !(k === 'maritalStatusOther' && formData.maritalStatus !== 'אחר'))
      .filter(([k]) => !(k === 'additionalInfo' && formData.interestedInGroup !== 'כתיבת פרטים נוספים'))
      .filter(([_, v]) => !v.toString().trim());
    if (empty.length > 0) {
      setError(`נא למלא את כל השדות (חסר: ${empty.map(([k]) => fieldLabels[k]).join(', ')})`);
      window.scrollTo({ top: 0, behavior: 'smooth' });
      return false;
    }
    if (!formData.consent) {
      setError('יש לאשר את תיבת ההסכמה כדי להמשיך');
      window.scrollTo({ top: 0, behavior: 'smooth' });
      return false;
    }
    return true;
  };

  const handleSubmit = async () => {
    if (!validate()) return;

    if (!WEBHOOK_URL) {
      setError('הטופס עדיין לא מחובר למערכת. נא לפנות למנהל המערכת.');
      window.scrollTo({ top: 0, behavior: 'smooth' });
      return;
    }

    setError('');
    setSubmissionStatus('submitting');
    setErrorMessage('');

    try {
      // שליחה דרך טופס מוסתר ל-iframe סמוי - עוקף חסימת CORS
      // הסקריפט קולט את ה-formData בפורמט form-encoded
      const iframe = document.createElement('iframe');
      iframe.name = 'fym_submit_target_' + Date.now();
      iframe.style.display = 'none';
      document.body.appendChild(iframe);

      const form = document.createElement('form');
      form.method = 'POST';
      form.action = WEBHOOK_URL;
      form.target = iframe.name;
      form.style.display = 'none';

      // מעבירים את כל הנתונים כשדה אחד בשם data (JSON)
      const input = document.createElement('input');
      input.type = 'hidden';
      input.name = 'data';
      input.value = JSON.stringify(formData);
      form.appendChild(input);

      document.body.appendChild(form);
      form.submit();

      // ניקוי אחרי 3 שניות
      setTimeout(() => {
        document.body.removeChild(form);
        document.body.removeChild(iframe);
      }, 3000);

      setSubmissionStatus('success');
      window.scrollTo({ top: 0, behavior: 'smooth' });

    } catch (err) {
      setSubmissionStatus('error');
      setErrorMessage(err.message || 'אירעה שגיאה בשליחה. נא לנסות שוב.');
      window.scrollTo({ top: 0, behavior: 'smooth' });
    }
  };

  const resetForm = () => {
    setFormData({
      childName: '', gender: '', fatherName: '', motherName: '',
      maritalStatus: '', maritalStatusOther: '', address: '', age: '',
      grade: '', healthFund: '', birthDate: '',
      specialEducation: '', specialEducationDetails: '',
      interestedInGroup: '', additionalInfo: '', consent: false
    });
    setSubmissionStatus('idle');
    setError('');
    setErrorMessage('');
    window.scrollTo({ top: 0, behavior: 'smooth' });
  };

  const inputClass = "w-full px-4 py-3 bg-white border border-slate-300 rounded-lg text-slate-800 text-base placeholder-slate-400 focus:outline-none focus:ring-2 focus:ring-teal-500 focus:border-transparent transition-all";
  const labelClass = "block text-sm font-semibold text-slate-700 mb-2";
  const radioGroupClass = "flex flex-wrap gap-2";
  const radioLabelClass = (selected) =>
    `flex-1 min-w-fit px-4 py-2.5 border-2 rounded-lg text-center cursor-pointer transition-all text-sm font-medium ${
      selected
        ? 'border-teal-600 bg-teal-50 text-teal-800'
        : 'border-slate-200 bg-white text-slate-600 hover:border-teal-300 hover:bg-teal-50/50'
    }`;

  const RadioGroup = ({ field, options }) => (
    <div className={radioGroupClass}>
      {options.map(opt => (
        <label key={opt} className={radioLabelClass(formData[field] === opt)}>
          <input
            type="radio"
            name={field}
            value={opt}
            checked={formData[field] === opt}
            onChange={(e) => handleChange(field, e.target.value)}
            className="sr-only"
          />
          {opt}
        </label>
      ))}
    </div>
  );

  // ===== מסך תודה אחרי שליחה מוצלחת =====
  if (submissionStatus === 'success') {
    return (
      <div dir="rtl" className="min-h-screen bg-gradient-to-b from-slate-50 to-teal-50/30 py-8 px-4 font-sans flex items-start sm:items-center justify-center">
        <div className="max-w-xl w-full">
          <div className="bg-white rounded-2xl shadow-sm border border-slate-100 overflow-hidden">
            <div className="px-6 py-8 flex flex-col items-center text-center">
              <img
                src={FYM_LOGO}
                alt="FYM"
                className="w-28 h-28 object-contain mb-2"
              />
            </div>

            <div className="px-6 sm:px-10 pb-10 text-center">
              <div className="w-20 h-20 bg-emerald-100 rounded-full flex items-center justify-center mx-auto mb-5">
                <CheckCircle2 className="text-emerald-600" size={48} strokeWidth={2} />
              </div>

              <h1 className="text-2xl sm:text-3xl font-bold text-slate-800 mb-3">
                פנייתך התקבלה בהצלחה
              </h1>

              <p className="text-slate-600 leading-relaxed mb-2">
                תודה שמילאת את הטופס.
              </p>
              <p className="text-slate-600 leading-relaxed mb-8">
                נציג/ה מהמרפאה ייצור איתך קשר בהקדם.
              </p>

              <button
                onClick={resetForm}
                className="text-teal-700 hover:text-teal-900 text-sm font-medium py-2 inline-flex items-center gap-1.5 transition-colors"
              >
                <RotateCcw size={14} />
                למילוי טופס נוסף
              </button>
            </div>
          </div>

          <p className="text-center text-xs text-slate-400 mt-6">
            FYM Clinic | fym-clinic.co.il
          </p>
        </div>
      </div>
    );
  }

  // ===== טופס רגיל =====

  return (
    <div dir="rtl" className="min-h-screen bg-gradient-to-b from-slate-50 to-teal-50/30 py-8 px-4 font-sans">
      <div className="max-w-2xl mx-auto">

        {/* Header */}
        <div className="bg-white rounded-2xl shadow-sm border border-slate-100 overflow-hidden mb-6">
          <div className="px-6 py-8 flex flex-col items-center text-center">
            <img
              src={FYM_LOGO}
              alt="FYM - Free Your Mind"
              className="w-36 h-36 sm:w-40 sm:h-40 object-contain mb-4"
            />
            <h1 className="text-xl sm:text-2xl font-bold text-slate-800 mb-1">
              טופס פרטים לסדנה
            </h1>
            <p className="text-sm text-slate-500">
              מרפאת בריאות הנפש | fym-clinic.co.il
            </p>
          </div>
          <div className="bg-teal-50/60 px-6 py-4 border-t border-teal-100">
            <p className="text-slate-700 text-sm leading-relaxed text-center">
              אנא מלאו את הפרטים הבאים. בסיום הטופס, פנייתכם תישלח אלינו ונחזור אליכם בהקדם.
            </p>
          </div>
        </div>

        {/* Error - validation */}
        {error && (
          <div className="mb-6 bg-rose-50 border border-rose-200 rounded-xl p-4 flex items-start gap-3">
            <AlertCircle className="text-rose-600 flex-shrink-0 mt-0.5" size={20} />
            <p className="text-rose-800 text-sm">{error}</p>
          </div>
        )}

        {/* Error - submission failure */}
        {submissionStatus === 'error' && (
          <div className="mb-6 bg-rose-50 border-2 border-rose-300 rounded-xl p-4 flex items-start gap-3">
            <AlertCircle className="text-rose-600 flex-shrink-0 mt-0.5" size={20} />
            <div className="flex-1">
              <p className="text-rose-900 text-sm font-semibold mb-1">השליחה נכשלה</p>
              <p className="text-rose-800 text-sm">{errorMessage} — נא ללחוץ על "שליחה" שוב.</p>
            </div>
          </div>
        )}

        {/* Form */}
        <div className="bg-white rounded-2xl shadow-sm border border-slate-100 p-6 sm:p-8 space-y-6">

          {/* 1. שם הילד */}
          <div>
            <label className={labelClass}>1. שם הילד/ה</label>
            <input
              type="text"
              value={formData.childName}
              onChange={(e) => handleChange('childName', e.target.value)}
              className={inputClass}
              placeholder="שם פרטי ושם משפחה"
            />
          </div>

          {/* 2. בן/בת */}
          <div>
            <label className={labelClass}>2. בן / בת</label>
            <RadioGroup field="gender" options={['בן', 'בת']} />
          </div>

          {/* 3. שם האב */}
          <div>
            <label className={labelClass}>3. שם מלא של האב</label>
            <input
              type="text"
              value={formData.fatherName}
              onChange={(e) => handleChange('fatherName', e.target.value)}
              className={inputClass}
              placeholder="שם פרטי ושם משפחה"
            />
          </div>

          {/* 4. שם האם */}
          <div>
            <label className={labelClass}>4. שם מלא של האם</label>
            <input
              type="text"
              value={formData.motherName}
              onChange={(e) => handleChange('motherName', e.target.value)}
              className={inputClass}
              placeholder="שם פרטי ושם משפחה"
            />
          </div>

          {/* 5. הורים נשואים/גרושים */}
          <div>
            <label className={labelClass}>5. סטטוס משפחתי</label>
            <RadioGroup field="maritalStatus" options={['נשואים', 'גרושים', 'אחר']} />

            {formData.maritalStatus === 'אחר' && (
              <div className="mt-3 animate-in fade-in slide-in-from-top-1 duration-200">
                <label className="block text-xs font-medium text-slate-600 mb-1.5">
                  פירוט (לדוגמה: אלמן/ה, פרודים, ידועים בציבור)
                </label>
                <input
                  type="text"
                  value={formData.maritalStatusOther}
                  onChange={(e) => handleChange('maritalStatusOther', e.target.value)}
                  className={inputClass}
                  placeholder="פרט/י את הסטטוס המשפחתי"
                />
              </div>
            )}
          </div>

          {/* 6. כתובת */}
          <div>
            <label className={labelClass}>6. כתובת מדויקת</label>
            <input
              type="text"
              value={formData.address}
              onChange={(e) => handleChange('address', e.target.value)}
              className={inputClass}
              placeholder="רחוב, מספר בית, עיר"
            />
          </div>

          {/* 7. גיל */}
          <div>
            <label className={labelClass}>7. גיל הילד/ה</label>
            <input
              type="number"
              min="0"
              max="25"
              value={formData.age}
              onChange={(e) => handleChange('age', e.target.value)}
              className={inputClass}
              placeholder="גיל בשנים"
            />
          </div>

          {/* 8. כיתה/גן */}
          <div>
            <label className={labelClass}>8. כיתה / גן</label>
            <input
              type="text"
              value={formData.grade}
              onChange={(e) => handleChange('grade', e.target.value)}
              className={inputClass}
              placeholder="לדוגמה: כיתה ג', גן חובה"
            />
          </div>

          {/* 9. קופת חולים */}
          <div>
            <label className={labelClass}>9. קופת חולים</label>
            <RadioGroup field="healthFund" options={['מכבי', 'כללית', 'מאוחדת', 'לאומית']} />
          </div>

          {/* 10. תאריך לידה */}
          <div>
            <label className={labelClass}>10. תאריך לידה</label>
            <input
              type="text"
              inputMode="numeric"
              value={formData.birthDate}
              onChange={(e) => {
                let val = e.target.value.replace(/\D/g, '');
                if (val.length >= 3) val = val.slice(0, 2) + '/' + val.slice(2);
                if (val.length >= 6) val = val.slice(0, 5) + '/' + val.slice(5, 9);
                handleChange('birthDate', val);
              }}
              className={inputClass}
              placeholder="DD/MM/YYYY"
              maxLength={10}
            />
          </div>

          {/* 11. חינוך מיוחד */}
          <div>
            <label className={labelClass}>11. חינוך מיוחד</label>
            <RadioGroup field="specialEducation" options={['כן', 'לא']} />

            {formData.specialEducation === 'כן' && (
              <div className="mt-3 animate-in fade-in slide-in-from-top-1 duration-200">
                <label className="block text-xs font-medium text-slate-600 mb-1.5">
                  פירוט (סוג מסגרת, אבחנה רלוונטית, צרכים מיוחדים)
                </label>
                <textarea
                  value={formData.specialEducationDetails}
                  onChange={(e) => handleChange('specialEducationDetails', e.target.value)}
                  className={`${inputClass} min-h-[90px] resize-y`}
                  placeholder="לדוגמה: כיתה תקשורתית בבית ספר רגיל, אבחון ASD, מקבל/ת תמיכה בשעות שילוב"
                  rows={3}
                />
              </div>
            )}
          </div>

          {/* 12. מעוניינים בקבוצה */}
          <div>
            <label className={labelClass}>12. האם מעוניינים בהצטרפות לטיפול רגשי בקבוצה עבור הילד/ה?</label>
            <RadioGroup field="interestedInGroup" options={['כן', 'לא', 'כתיבת פרטים נוספים']} />

            {formData.interestedInGroup === 'כתיבת פרטים נוספים' && (
              <div className="mt-3 animate-in fade-in slide-in-from-top-1 duration-200">
                <label className="block text-xs font-medium text-slate-600 mb-1.5">
                  לידיעת המרפאה
                </label>
                <textarea
                  value={formData.additionalInfo}
                  onChange={(e) => handleChange('additionalInfo', e.target.value)}
                  className={`${inputClass} min-h-[90px] resize-y`}
                  placeholder="כל מידע נוסף שחשוב לכם שהמרפאה תדע"
                  rows={3}
                />
              </div>
            )}
          </div>

          {/* הסכמה */}
          <div className="pt-2">
            <div className="bg-slate-50 border border-slate-200 rounded-xl p-5">
              <h3 className="text-sm font-bold text-slate-800 mb-3">
                הסכמה לאיסוף ושמירת מידע
              </h3>
              <div className="text-sm text-slate-700 leading-relaxed space-y-2 mb-4">
                <p>
                  כהורה/אפוטרופוס חוקי של הילד/ה, אני מאשר/ת ל-FYM לאסוף ולשמור את הפרטים שמסרתי במאגר מידע מאובטח, לצורך יצירת קשר, תיאום פגישה והתאמת השירות הטיפולי. ידוע לי כי:
                </p>
                <ul className="space-y-1.5 pr-4">
                  <li className="flex gap-2">
                    <span className="text-teal-600 flex-shrink-0">•</span>
                    <span>המידע לא יועבר לצדדים שלישיים ללא הסכמתי, למעט כנדרש על פי דין</span>
                  </li>
                  <li className="flex gap-2">
                    <span className="text-teal-600 flex-shrink-0">•</span>
                    <span>עומדת לי הזכות לעיין במידע, לתקנו ולבקש את מחיקתו בפנייה ל-{FYM_EMAIL}</span>
                  </li>
                  <li className="flex gap-2">
                    <span className="text-teal-600 flex-shrink-0">•</span>
                    <span>ניתן לחזור בי מההסכמה בכל עת</span>
                  </li>
                </ul>
                <p className="text-xs text-slate-500 pt-1">
                  ההסכמה ניתנת בהתאם לחוק הגנת הפרטיות, התשמ"א-1981.
                </p>
              </div>

              <label className="flex items-start gap-3 cursor-pointer group bg-white border-2 border-slate-300 rounded-lg p-3 hover:border-teal-400 transition-all has-[:checked]:border-teal-600 has-[:checked]:bg-teal-50">
                <input
                  type="checkbox"
                  checked={formData.consent}
                  onChange={(e) => handleChange('consent', e.target.checked)}
                  className="mt-0.5 w-5 h-5 rounded border-2 border-slate-400 text-teal-600 focus:ring-2 focus:ring-teal-500 cursor-pointer flex-shrink-0 accent-teal-600"
                />
                <span className="text-sm font-semibold text-slate-800 leading-relaxed">
                  קראתי, הבנתי ואני נותן/ת את הסכמתי <span className="text-rose-600">*</span>
                </span>
              </label>
            </div>
          </div>

          {/* Submit button */}
          <button
            onClick={handleSubmit}
            disabled={submissionStatus === 'submitting'}
            className="w-full bg-teal-600 hover:bg-teal-700 active:bg-teal-800 disabled:bg-teal-400 disabled:cursor-not-allowed text-white font-semibold py-4 rounded-xl transition-all flex items-center justify-center gap-2 shadow-sm hover:shadow-md mt-4"
          >
            {submissionStatus === 'submitting' ? (
              <>
                <Loader2 size={20} className="animate-spin" />
                שולח...
              </>
            ) : (
              <>
                <Send size={20} />
                שליחה
              </>
            )}
          </button>
        </div>

        {/* Footer */}
        <p className="text-center text-xs text-slate-400 mt-8">
          FYM Clinic | fym-clinic.co.il
        </p>
      </div>
    </div>
  );
}
